using Microsoft.EntityFrameworkCore;
using Microsoft.Azure.Cosmos;

class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseCosmos(
            "https://localhost:8081",
            "C2y6yDjf5/R+ob0N8A7Cgv30VRDJIWEHLM+4QDU5DE2nQ9nDuVTqobD4b8mGGyPMbIZnqyMsEcaGQy67XIw/Jw==",
            "CatalogDb");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 breaking change: The Cosmos provider now uses "$type" as the
        // discriminator property name by default (was "Discriminator" in EF Core 8).
        // Existing documents already have "Discriminator" so we must explicitly
        // configure the old property name to avoid data loss / query failures.
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");
            b.HasDiscriminator<string>("Discriminator");
        });
    }
}

class Product
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
}

// EF Core 9 breaking change: Synchronous I/O on the Cosmos DB provider now throws
// InvalidOperationException by default. All queries must use async methods.
class ProductService
{
    private readonly CosmosDbContext _db;

    public ProductService(CosmosDbContext db) => _db = db;

    // BEFORE (throws in EF Core 9):
    //   var products = _db.Products.ToList();
    //   var first = _db.Products.First(p => p.Name == name);

    // AFTER (use async equivalents):
    public async Task<List<Product>> GetAllAsync()
        => await _db.Products.ToListAsync();

    public async Task<Product> GetByNameAsync(string name)
        => await _db.Products.FirstAsync(p => p.Name == name);
}

